<!-- wp:heading {"className":"has-gray-400-color has-text-color has-link-color","style":{"elements":{"link":{"color":{"text":"var:preset|color|grey-dark"}}},"typography":{"fontStyle":"normal","fontWeight":"400","textAlign":"center"}},"textColor":"grey-dark"} -->
<h2 class="wp-block-heading has-text-align-center has-gray-400-color has-text-color has-link-color has-grey-dark-color" style="font-style:normal;font-weight:400">Your Documents,<br><em><mark style="background-color:rgba(0, 0, 0, 0)" class="has-inline-color has-primary-light-color"><em><em>Our Expertise</em></em></mark></em></h2>
<!-- /wp:heading -->

<!-- wp:paragraph {"style":{"elements":{"link":{"color":{"text":"var:preset|color|tertiary"},":hover":{"color":{"text":"var:preset|color|tertiary"}}}},"typography":{"textAlign":"center"},"spacing":{"margin":{"top":"var:preset|spacing|50","bottom":"var:preset|spacing|60"}}},"textColor":"black","fontSize":"medium"} -->
<p class="has-text-align-center has-black-color has-text-color has-link-color has-medium-font-size" style="margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--60)">We specialize in navigating the document apostille process for our clients with speed and accuracy. Contact us for a free consultation – phone us toll-free at <a href="tel:1-888-433-1011">1-888-433-1011</a> or fill out our quick <a href="https://idocs.local/get-in-touch/">Get Started</a> form. We’ll explain the process, answer your questions, and discuss your options.</p>
<!-- /wp:paragraph --></header>
<!-- /wp:group -->

<!-- wp:group {"metadata":{"name":"Two Content Columns"},"align":"wide","className":"is-two-columns","style":{"spacing":{"margin":{"top":"var:preset|spacing|50"}}},"layout":{"type":"constrained"}} -->
<div class="wp-block-group alignwide is-two-columns" style="margin-top:var(--wp--preset--spacing--50)"><!-- wp:group {"metadata":{"name":"Content Column"},"style":{"spacing":{"blockGap":"var:preset|spacing|40"}},"layout":{"type":"constrained"}} -->
<div class="wp-block-group"><!-- wp:heading {"level":3,"fontSize":"heading-small"} -->
<h3 class="wp-block-heading has-heading-small-font-size">What is an apostille?</h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">The term apostille is used to describe the process of having a document specially certified by a government authority, so it will be accepted in a foreign jurisdiction. Many countries have signed on to the Hague Apostille Convention, abolishing the need for additional diplomatic legalization.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">After a document has been apostilled, it will be recognized in every country that has signed the Hague Apostille Convention.</p>
<!-- /wp:paragraph --></div>
<!-- /wp:group -->

<!-- wp:group {"metadata":{"name":"Content Column"},"style":{"spacing":{"blockGap":"var:preset|spacing|40"}},"layout":{"type":"constrained"}} -->
<div class="wp-block-group"><!-- wp:heading {"level":3,"fontSize":"heading-small"} -->
<h3 class="wp-block-heading has-heading-small-font-size">How do I get an apostille?</h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size">In Canada, the document apostille process typically involves two steps:</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph -->
<p><strong>Step 1</strong>&nbsp;– preparing your documents – this may include ordering new documents, notarization, or translation.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"fontSize":"medium"} -->
<p class="has-medium-font-size"><strong>Step 2</strong>&nbsp; – document apostille – this step involves having your documents&nbsp;apostilled&nbsp;by the appropriate government authority.</p>
<!-- /wp:paragraph --></div>
<!-- /wp:group --></div>
<!-- /wp:group --></div>
<!-- /wp:group --></section>
<!-- /wp:group -->

<!-- wp:group {"tagName":"section","metadata":{"name":"About the Process","categories":["idc-sections-en"],"patternName":"idc-block-theme/about-the-process-2-col-en"},"align":"full","className":"is-style-beige","layout":{"type":"constrained"}} -->
<section class="wp-block-group alignfull is-style-beige"><!-- wp:group {"tagName":"header","metadata":{"name":"Section Heading: Center"},"align":"wide","layout":{"type":"constrained"}} -->
<header class="wp-block-group alignwide"><!-- wp:paragraph {"className":"has-thin-lines","style":{"typography":{"textAlign":"center"}}} -->
<p class="has-text-align-center has-thin-lines">The Process</p>
<!-- /wp:paragraph -->

<!-- wp:heading {"className":"has-gray-400-color has-text-color has-link-color","style":{"elements":{"link":{"color":{"text":"var:preset|color|grey-dark"}}},"typography":{"fontStyle":"normal","fontWeight":"400","textAlign":"center"}},"textColor":"grey-dark"} -->
<h2 class="wp-block-heading has-text-align-center has-gray-400-color has-text-color has-link-color has-grey-dark-color" style="font-style:normal;font-weight:400">Document<br><em><mark style="background-color:rgba(0, 0, 0, 0)" class="has-inline-color has-primary-light-color"><em>Apostille Process</em></mark></em></h2>
<!-- /wp:heading -->

<!-- wp:paragraph {"style":{"elements":{"link":{"color":{"text":"var:preset|color|black"}}},"typography":{"textAlign":"center"},"spacing":{"margin":{"top":"var:preset|spacing|50","bottom":"var:preset|spacing|60"}}},"textColor":"black","fontSize":"medium"} -->
<p class="has-text-align-center has-black-color has-text-color has-link-color has-medium-font-size" style="margin-top:var(--wp--preset--spacing--50);margin-bottom:var(--wp--preset--spacing--60)">To have a document recognized abroad, it must go through the apostille process. This allows acceptance in countries that follow the Apostille Convention. For such destinations, the Apostille process applies and involves the following steps.</p>
<!-- /wp:paragraph --></header>
<!-- /wp:group -->

